code = """import json, re
# Load clinical data
clinical_var = var_call_eDQ7Vn0GzpLYUzsx94nMbAac
if isinstance(clinical_var, str):
    with open(clinical_var, 'r') as f:
        clinical = json.load(f)
else:
    clinical = clinical_var

# Load mutation data
mut_var = var_call_HCK6YElIATe4KnXfMAJ8XExa
if isinstance(mut_var, str):
    with open(mut_var, 'r') as f:
        mutations = json.load(f)
else:
    mutations = mut_var

# Extract CDH1 mutation participant barcodes
mut_barcodes = set()
for r in mutations:
    pb = r.get('ParticipantBarcode') or r.get('participantbarcode')
    if pb:
        mut_barcodes.add(pb.strip().upper())

# Extract patient barcodes and histological types from clinical entries
barcode_pattern = re.compile(r'(TCGA-[A-Za-z0-9]+-[A-Za-z0-9]+)')
hist_to_barcodes = {}
all_rows = 0
for r in clinical:
    all_rows += 1
    desc = r.get('Patient_description') or r.get('patient_description') or r.get('Patient_description')
    hist = r.get('histological_type') or r.get('histologicaltype') or r.get('histological_type')
    if not desc or not hist:
        continue
    m = barcode_pattern.search(desc)
    if not m:
        continue
    barcode = m.group(1).strip().upper()
    # normalize: some barcodes in mutations may be like TCGA-06-0210 vs TCGA-06-0210 (same)
    hist = hist.strip()
    hist_to_barcodes.setdefault(hist, set()).add(barcode)

# Compute percentages
results = []
for hist, barcodes in hist_to_barcodes.items():
    total = len(barcodes)
    if total == 0:
        continue
    mutated = len([b for b in barcodes if b in mut_barcodes])
    percent = (mutated / total) * 100
    results.append({'histological_type': hist, 'total_alive_patients': total, 'mutated_patients': mutated, 'percent_mutated': round(percent, 2)})

# Sort by percent desc then mutated count desc then histological_type
results_sorted = sorted(results, key=lambda x: (-x['percent_mutated'], -x['mutated_patients'], x['histological_type']))

top3 = results_sorted[:3]

print("__RESULT__:")
print(json.dumps(top3))"""

